#!/usr/bin/env node
/**
 * Knowledge Graph Validation Script
 * Validates the OpenCoreSDK knowledge graph for correctness, completeness, and quality
 */

const fs = require('fs');
const path = require('path');

// Valid types
const VALID_NODE_TYPES = [
  'file', 'function', 'class', 'module', 'concept', 'config', 'document',
  'service', 'table', 'endpoint', 'pipeline', 'schema', 'resource',
  'domain', 'flow', 'step'
];

const VALID_EDGE_TYPES = [
  'imports', 'exports', 'contains', 'inherits', 'implements', 'calls',
  'subscribes', 'publishes', 'middleware', 'reads_from', 'writes_to',
  'transforms', 'validates', 'depends_on', 'tested_by', 'configures',
  'related', 'similar_to', 'deploys', 'serves', 'migrates', 'documents',
  'provisions', 'routes', 'defines_schema', 'triggers', 'contains_flow',
  'flow_step', 'cross_domain'
];

const VALID_COMPLEXITY = ['simple', 'moderate', 'complex'];
const VALID_DIRECTIONS = ['forward', 'backward', 'bidirectional'];
const VALID_PREFIXES = [
  'file:', 'function:', 'class:', 'module:', 'concept:', 'config:',
  'document:', 'service:', 'table:', 'endpoint:', 'pipeline:',
  'schema:', 'resource:', 'domain:', 'flow:', 'step:'
];

// File paths
const DOMAIN_GRAPH_PATH = process.argv[2];
const LAYERS_PATH = path.join(path.dirname(DOMAIN_GRAPH_PATH), 'intermediate', 'layers.json');

function loadJSON(filePath) {
  try {
    const content = fs.readFileSync(filePath, 'utf8');
    return JSON.parse(content);
  } catch (err) {
    console.error(`Error loading ${filePath}: ${err.message}`, filePath);
    process.exit(1);
  }
}

function main() {
  const outputPath = process.argv[3];
  const graph = loadJSON(DOMAIN_GRAPH_PATH);

  const issues = [];
  const warnings = [];
  const stats = {
    totalNodes: 0,
    totalEdges: 0,
    totalLayers: 0,
    tourSteps: 0,
    nodeTypes: {},
    edgeTypes: {}
  };

  // Build set of all node IDs
  const nodeIds = new Set();
  const nodeMap = new Map();

  // Detect if this is a domain graph
  const isDomainGraph = graph.nodes && graph.nodes.some(n => n.type === 'domain' || n.type === 'flow' || n.type === 'step');

  // ============================================
  // Check 1: Schema Validation
  // ============================================

  // Validate nodes
  if (graph.nodes) {
    stats.totalNodes = graph.nodes.length;

    for (let i = 0; i < graph.nodes.length; i++) {
      const node = graph.nodes[i];
      nodeMap.set(node.id, i);

      // Check required fields
      if (!node.id || typeof node.id !== 'string') {
        issues.push(`Node at index ${i} missing or invalid 'id' field`);
      }
      if (!node.type || typeof node.type !== 'string') {
        issues.push(`Node '${node.id || i}' missing or invalid 'type' field`);
      } else if (!VALID_NODE_TYPES.includes(node.type)) {
        issues.push(`Node '${node.id}' has invalid type '${node.type}'`);
      }
      if (!node.name || typeof node.name !== 'string') {
        issues.push(`Node '${node.id}' missing or invalid 'name' field`);
      }
      if (!node.summary || typeof node.summary !== 'string') {
        issues.push(`Node '${node.id}' missing or invalid 'summary' field`);
      }
      if (!Array.isArray(node.tags) || node.tags.length === 0) {
        issues.push(`Node '${node.id}' missing or empty 'tags' array`);
      }
      if (node.complexity && !VALID_COMPLEXITY.includes(node.complexity)) {
        issues.push(`Node '${node.id}' has invalid complexity '${node.complexity}'`);
      }

      // Check ID prefix matches type
      if (node.id && node.type) {
        const expectedPrefix = node.type + ':';
        if (!node.id.startsWith(expectedPrefix)) {
          warnings.push(`Node '${node.id}' type='${node.type}' but ID does not start with '${expectedPrefix}'`);
        }
      }

      // Track node types
      if (node.type) {
        stats.nodeTypes[node.type] = (stats.nodeTypes[node.type] || 0) + 1;
      }
    }
  }

  // Validate edges
  if (graph.edges) {
    stats.totalEdges = graph.edges.length;

    for (let i = 0; i < graph.edges.length; i++) {
      const edge = graph.edges[i];

      if (!edge.source || typeof edge.source !== 'string') {
        issues.push(`Edge at index ${i} missing or invalid 'source' field`);
      }
      if (!edge.target || typeof edge.target !== 'string') {
        issues.push(`Edge at index ${i} missing or invalid 'target' field`);
      }
      if (!edge.type || typeof edge.type !== 'string') {
        issues.push(`Edge at index ${i} missing or invalid 'type' field`);
      } else if (!VALID_EDGE_TYPES.includes(edge.type)) {
        issues.push(`Edge at index ${i} has invalid type '${edge.type}'`);
      }
      if (edge.direction && !VALID_DIRECTIONS.includes(edge.direction)) {
        issues.push(`Edge at index ${i} has invalid direction '${edge.direction}'`);
      }
      if (edge.weight !== undefined && (typeof edge.weight !== 'number' || edge.weight < 0 || edge.weight > 1)) {
        issues.push(`Edge at index ${i} has invalid weight '${edge.weight}' (must be 0.0-1.0)`);
      }

      // Track edge types
      if (edge.type) {
        stats.edgeTypes[edge.type] = (stats.edgeTypes[edge.type] || 0) + 1;
      }
    }
  }

  // ============================================
  // Check 2: Referential Integrity
  // ============================================

  if (graph.edges) {
    for (let i = 0; i < graph.edges.length; i++) {
      const edge = graph.edges[i];
      if (edge.source && !nodeIds.has(edge.source) && !graph.nodes?.some(n => n.id === edge.source)) {
        issues.push(`Edge at index ${i} references non-existent source node '${edge.source}'`);
      }
      if (edge.target && !nodeIds.has(edge.target) && !graph.nodes?.some(n => n.id === edge.target)) {
        issues.push(`Edge at index ${i} references non-existent target node '${edge.target}'`);
      }
    }
  }

  // Check layers nodeIds references
  if (graph.layers) {
    stats.totalLayers = graph.layers.length;
    for (let i = 0; i < graph.layers.length; i++) {
      const layer = graph.layers[i];
      if (layer.nodeIds) {
        for (const nodeId of layer.nodeIds) {
          if (!graph.nodes?.some(n => n.id === nodeId)) {
            issues.push(`Layer '${layer.id}' references non-existent node '${nodeId}'`);
          }
        }
      }
    }
  }

  // Check tour steps nodeIds references
  if (graph.tour) {
    stats.tourSteps = graph.tour.length;
    for (let i = 0; i < graph.tour.length; i++) {
      const step = graph.tour[i];
      if (step.nodeIds) {
        for (const nodeId of step.nodeIds) {
          if (!graph.nodes?.some(n => n.id === nodeId)) {
            issues.push(`Tour step ${i} references non-existent node '${nodeId}'`);
          }
        }
      }
    }
  }

  // ============================================
  // Check 3: Completeness
  // ============================================

  if (!graph.nodes || graph.nodes.length === 0) {
    issues.push('Graph has no nodes');
  }
  if (!graph.edges || graph.edges.length === 0) {
    issues.push('Graph has no edges');
  }

  // Layers check - relaxed for domain graphs
  if (!isDomainGraph) {
    if (!graph.layers || graph.layers.length === 0) {
      issues.push('Graph has no layers');
    }
  } else if (!graph.layers || graph.layers.length === 0) {
    warnings.push('Domain graph has no layers defined (acceptable for domain graphs)');
  }

  // Tour check - relaxed for domain graphs
  if (!isDomainGraph) {
    if (!graph.tour || graph.tour.length === 0) {
      issues.push('Graph has no tour steps');
    }
  } else if (!graph.tour || graph.tour.length === 0) {
    warnings.push('Domain graph has no tour defined (acceptable for domain graphs)');
  }

  // ============================================
  // Check 4: Layer Coverage (for structural graphs)
  // ============================================

  const fileLevelTypes = ['file', 'config', 'document', 'service', 'pipeline', 'table', 'schema', 'resource', 'endpoint'];
  if (!isDomainGraph && graph.layers && graph.nodes) {
    const fileNodes = graph.nodes.filter(n => fileLevelTypes.includes(n.type));
    const nodesInLayers = new Set();

    for (const layer of graph.layers) {
      if (layer.nodeIds) {
        for (const nodeId of layer.nodeIds) {
          if (nodesInLayers.has(nodeId)) {
            issues.push(`Node '${nodeId}' appears in multiple layers`);
          }
          nodesInLayers.add(nodeId);
        }
      } else {
        issues.push(`Layer '${layer.id}' has empty nodeIds array`);
      }
    }

    for (const node of fileNodes) {
      if (!nodesInLayers.has(node.id)) {
        issues.push(`File-level node '${node.id}' is missing from all layers`);
      }
    }
  }

  // ============================================
  // Check 5: Uniqueness
  // ============================================

  if (graph.nodes) {
    const seenIds = new Map();
    for (let i = 0; i < graph.nodes.length; i++) {
      const id = graph.nodes[i].id;
      if (id) {
        if (seenIds.has(id)) {
          issues.push(`Duplicate node ID '${id}' at indices ${seenIds.get(id)} and ${i}`);
        }
        seenIds.set(id, i);
      }
    }
  }

  // ============================================
  // Check 6: Tour Validation
  // ============================================

  if (graph.tour && graph.tour.length > 0) {
    const orders = graph.tour.map(s => s.order).filter(o => o !== undefined);
    const uniqueOrders = new Set(orders);

    if (orders.length !== uniqueOrders.size) {
      warnings.push('Tour has duplicate order values');
    }

    // Check sequential starting from 1
    const sortedOrders = [...orders].sort((a, b) => a - b);
    for (let i = 0; i < sortedOrders.length; i++) {
      if (sortedOrders[i] !== i + 1) {
        warnings.push('Tour steps do not have sequential order values starting from 1');
        break;
      }
    }

    if (graph.tour.length < 5) {
      warnings.push(`Tour has only ${graph.tour.length} steps (recommended: 5-15)`);
    } else if (graph.tour.length > 15) {
      warnings.push(`Tour has ${graph.tour.length} steps (recommended: 5-15)`);
    }

    for (const step of graph.tour) {
      if (!step.nodeIds || step.nodeIds.length === 0) {
        warnings.push(`Tour step ${step.order} has no nodeIds`);
      }
    }
  }

  // ============================================
  // Check 7: Quality Checks
  // ============================================

  if (graph.nodes) {
    for (const node of graph.nodes) {
      // Check for generic/short summaries
      if (node.summary) {
        const filename = node.id?.split('/').pop() || '';
        if (node.summary.length < 20 || node.summary === filename) {
          warnings.push(`Node '${node.id}' has a generic or very short summary`);
        }
      }
    }
  }

  // Check for self-referencing edges
  if (graph.edges) {
    for (const edge of graph.edges) {
      if (edge.source === edge.target) {
        warnings.push(`Edge has self-referencing source and target '${edge.source}'`);
      }
    }
  }

  // Check for orphan nodes
  if (graph.nodes && graph.edges) {
    const connectedNodes = new Set();
    for (const edge of graph.edges) {
      connectedNodes.add(edge.source);
      connectedNodes.add(edge.target);
    }

    for (const node of graph.nodes) {
      if (!connectedNodes.has(node.id)) {
        warnings.push(`Node '${node.id}' has no edges connecting to or from it`);
      }
    }
  }

  // ============================================
  // Check 8: Non-Code Node Quality Checks
  // ============================================

  if (graph.nodes && graph.edges) {
    // Build edge type map for each node
    const nodeEdges = new Map();
    for (const edge of graph.edges) {
      if (!nodeEdges.has(edge.source)) nodeEdges.set(edge.source, []);
      if (!nodeEdges.has(edge.target)) nodeEdges.set(edge.target, []);
      nodeEdges.get(edge.source).push(edge.type);
      nodeEdges.get(edge.target).push(edge.type);
    }

    for (const node of graph.nodes) {
      const edges = nodeEdges.get(node.id) || [];

      if (node.type === 'document' && !edges.includes('documents')) {
        warnings.push(`Document node '${node.id}' has no 'documents' edges`);
      }
      if (node.type === 'service' && !edges.some(e => ['deploys', 'depends_on'].includes(e))) {
        warnings.push(`Service node '${node.id}' has no 'deploys' or 'depends_on' edges`);
      }
      if (node.type === 'pipeline' && !edges.includes('triggers')) {
        warnings.push(`Pipeline node '${node.id}' has no 'triggers' edges`);
      }
      if (node.type === 'table' && !edges.some(e => ['migrates', 'defines_schema'].includes(e))) {
        warnings.push(`Table node '${node.id}' has no 'migrates' or 'defines_schema' edges`);
      }
      if (node.type === 'schema' && !edges.includes('defines_schema')) {
        warnings.push(`Schema node '${node.id}' has no 'defines_schema' edges`);
      }
      if (node.type === 'domain' && !edges.includes('contains_flow')) {
        warnings.push(`Domain node '${node.id}' has no 'contains_flow' edges`);
      }
      if (node.type === 'flow' && !edges.includes('flow_step')) {
        warnings.push(`Flow node '${node.id}' has no 'flow_step' edges`);
      }
    }
  }

  // ============================================
  // Check 9: Additional checks from external layers.json
  // ============================================

  let layersData = null;
  try {
    layersData = loadJSON(LAYERS_PATH);
    if (layersData.layers) {
      stats.totalLayers = layersData.layers.length;
    }
  } catch (err) {
    warnings.push(`Could not load layers.json from ${LAYERS_PATH}: ${err.message}`);
  }

  // Write results
  const result = {
    scriptCompleted: true,
    issues,
    warnings,
    stats
  };

  fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
  console.log(`Validation complete. Issues: ${issues.length}, Warnings: ${warnings.length}`);
}

main();
